import React, {useState, useEffect} from 'react';

import styled from "styled-components";

import Posts from "../Models/Posts";

export default function Post(props){
  const [post, setPost] = useState({})
  const [update, setUpdate] = useState(false)

  const filterArr = () => {
    let idPost = window.location.pathname.split("/")[2];
    let arrfiltered = Object.values(Posts).filter(post => {
      return post.id === idPost
    });
    return setPost(arrfiltered[0]);
  }
  
  useEffect(()=>{
    filterArr(post);
    setUpdate(true)
  }, []);
  
  return (
    <Wrapper>
      <h1>Lucas</h1>
      {post ? <p>Teste</p> : <p>fonded</p>}
    </Wrapper>
  );
} 

const Wrapper = styled.div`
  width: 100%;
  background: #fff;
  box-shadow: 0px 2px 92px 0px rgba(0, 0, 0, 0.07);
  border-radius: 10px;
  padding: 30px;
`;